class Solution:
    def longestPalindromicSubsequence(self, s, k):
        def dist(a, b):
            d = abs(ord(a) - ord(b))
            return min(d, 26 - d)

        n = len(s)
        best = 0
        for mask in range(1, 1 << n):
            idxs = [i for i in range(n) if mask & (1 << i)]
            length = len(idxs)
            cost = 0
            lo, hi = 0, length - 1
            ok = True
            while lo < hi:
                cost += dist(s[idxs[lo]], s[idxs[hi]])
                if cost > k:
                    ok = False
                    break
                lo += 1
                hi -= 1
            if ok and length > best:
                best = length
        return best

