class Solution:
    def longestPalindromicSubsequence(self, s, k):
        import sys
        sys.setrecursionlimit(10000)
        from functools import lru_cache

        def dist(a, b):
            d = abs(ord(a) - ord(b))
            return min(d, 26 - d)

        n = len(s)

        @lru_cache(maxsize=None)
        def solve(i, j, budget):
            if i > j:
                return 0
            if i == j:
                return 1
            best = max(solve(i + 1, j, budget), solve(i, j - 1, budget))
            c = dist(s[i], s[j])
            if c <= budget:
                best = max(best, solve(i + 1, j - 1, budget - c) + 2)
            return best

        result = solve(0, n - 1, k)
        solve.cache_clear()
        return result

