var longestPalindromicSubsequence = function(s, k) {
    const n = s.length;
    function dist(a, b) {
        const d = Math.abs(a.charCodeAt(0) - b.charCodeAt(0));
        return Math.min(d, 26 - d);
    }
    const memo = new Map();
    function solve(i, j, budget) {
        if (i > j) return 0;
        if (i === j) return 1;
        const key = ((i * (n + 1) + j) * (k + 1)) + budget;
        if (memo.has(key)) return memo.get(key);
        let best = Math.max(solve(i + 1, j, budget), solve(i, j - 1, budget));
        const c = dist(s[i], s[j]);
        if (c <= budget) {
            best = Math.max(best, solve(i + 1, j - 1, budget - c) + 2);
        }
        memo.set(key, best);
        return best;
    }
    return solve(0, n - 1, k);
};
